const errorData = $input.first().json;
const workflowName = errorData.workflow?.name || 'Unknown';
const errorMessage = errorData.execution?.error?.message || 'Erreur inconnue';
const executionId = errorData.execution?.id || 'N/A';

return [{
  json: {
    content: "",
    embeds: [{
      title: "⚠️ Erreur Workflow",
      description: `**Workflow:** ${workflowName}\n**Erreur:** ${errorMessage}\n**Execution ID:** ${executionId}`,
      color: 15548997,
      footer: { text: "N8N Error Handler" },
      timestamp: new Date().toISOString()
    }]
  }
}];
